from django.shortcuts import render, redirect, get_object_or_404
from django.views.generic import TemplateView, View
from django.views.decorators.http import require_http_methods
from django.utils.decorators import method_decorator
from django.contrib.auth.decorators import login_required, user_passes_test
from django.contrib import messages
from django.contrib.auth.models import User
from django.db.models import Q
from django.db import transaction

from catalog.models import Barco
from reservations.models import Reserva, HistorialEstadoReserva
from .forms import BoatForm


def is_admin(user):
    return user.is_authenticated and user.is_staff


class AdminDashboardView(TemplateView):
    template_name = 'admin_panel/dashboard.html'

    @method_decorator(login_required(login_url='accounts:login'))
    @method_decorator(user_passes_test(is_admin))
    def dispatch(self, *args, **kwargs):
        return super().dispatch(*args, **kwargs)

    def get_context_data(self, **kwargs):
        context = super().get_context_data(**kwargs)
        context['total_barcos'] = Barco.objects.count()
        context['total_clientes'] = User.objects.filter(is_staff=False).count()
        context['total_reservas'] = Reserva.objects.count()
        context['reservas_pendientes'] = Reserva.objects.filter(estado='PENDIENTE_DE_PAGO').count()
        context['reservas_pagadas'] = Reserva.objects.filter(estado='PAGADO').count()
        context['reservas_en_uso'] = Reserva.objects.filter(estado='EN_USO').count()
        context['reservas_devueltas'] = Reserva.objects.filter(estado='DEVUELTO').count()
        return context


