            messages.error(request, f'No se puede eliminar el cliente "{cliente.email}" porque tiene reservas pendientes de pago.')
            return redirect('admin_panel:clients_list')

        email = cliente.email
        cliente.delete()
        messages.success(request, f'Cliente "{email}" eliminado exitosamente.')
        return redirect('admin_panel:clients_list')


class AdminReservationsListView(TemplateView):
    template_name = 'admin_panel/reservations_list.html'

    @method_decorator(login_required(login_url='accounts:login'))
    @method_decorator(user_passes_test(is_admin))
    def dispatch(self, *args, **kwargs):
        return super().dispatch(*args, **kwargs)

    def get_context_data(self, **kwargs):
        context = super().get_context_data(**kwargs)
        reservas = Reserva.objects.all().select_related('cliente', 'barco').order_by('-created_at')

        # Filtro por estado
        estado = self.request.GET.get('estado', '').strip()
        if estado:
            reservas = reservas.filter(estado=estado)

        # Filtro por cliente
        cliente_id = self.request.GET.get('cliente_id', '').strip()
        if cliente_id:
            try:
                reservas = reservas.filter(cliente_id=int(cliente_id))
            except (ValueError, TypeError):
                pass

        # Filtro por barco
        barco_id = self.request.GET.get('barco_id', '').strip()
        if barco_id:
            try:
                reservas = reservas.filter(barco_id=int(barco_id))
            except (ValueError, TypeError):
                pass

        # Búsqueda por código
        search = self.request.GET.get('search', '').strip()
        if search:
            reservas = reservas.filter(codigo_seguimiento__icontains=search)

        context['reservas'] = reservas
        context['estado'] = estado
        context['cliente_id'] = cliente_id
        context['barco_id'] = barco_id
        context['search'] = search
        context['estados'] = Reserva.ESTADO_CHOICES
        context['clientes'] = User.objects.filter(is_staff=False).order_by('email')
        context['barcos'] = Barco.objects.all().order_by('nombre')
        return context


