class AdminChangeReservationStatusView(View):
    @method_decorator(require_http_methods(['POST']))
    @method_decorator(login_required(login_url='accounts:login'))
    @method_decorator(user_passes_test(is_admin))
    def post(self, request, id):
        reserva = get_object_or_404(Reserva, id=id)
        nuevo_estado = request.POST.get('nuevo_estado', '').strip()
        notas = request.POST.get('notas', '').strip()

        # Validar que el nuevo estado sea válido
        estados_validos = [choice[0] for choice in Reserva.ESTADO_CHOICES]
        if nuevo_estado not in estados_validos:
            messages.error(request, 'Estado inválido.')
            return redirect('admin_panel:reservation_detail', id=id)

        if nuevo_estado == reserva.estado:
            messages.warning(request, 'El nuevo estado es igual al actual.')
            return redirect('admin_panel:reservation_detail', id=id)

        try:
            with transaction.atomic():
                estado_anterior = reserva.estado
                reserva.estado = nuevo_estado
                reserva.save()

                HistorialEstadoReserva.objects.create(
                    reserva=reserva,
                    estado_anterior=estado_anterior,
                    estado_nuevo=nuevo_estado,
                    cambio_por=request.user,
                    notas=notas,
                )

                messages.success(request, f'Estado de la reserva actualizado a {nuevo_estado}.')
        except Exception as e:
            messages.error(request, f'Error al actualizar el estado: {str(e)}')

        return redirect('admin_panel:reservation_detail', id=id)

from django.core.management.base import BaseCommand
from django.utils import timezone
from datetime import timedelta
from reservations.models import Reserva
from reservations.services.email import EmailService


class Command(BaseCommand):
    help = 'Envía recordatorios de pago a clientes con reservas pendientes que comienzan en 24 horas'

    def handle(self, *args, **options):
        # Obtener la fecha de mañana
        manana = timezone.now().date() + timedelta(days=1)

        # Buscar reservas en estado PENDIENTE_DE_PAGO que comienzan mañana
        reservas = Reserva.objects.filter(
            estado='PENDIENTE_DE_PAGO',
            fecha_inicio=manana
        )

        enviados = 0
        for reserva in reservas:
            try:
                EmailService.enviar_recordatorio_pago(reserva)
                enviados += 1
                self.stdout.write(
                    self.style.SUCCESS(
                        f'Recordatorio enviado a {reserva.email_cliente} para reserva {reserva.codigo_seguimiento}'
                    )
                )
            except Exception as e:
                self.stdout.write(
                    self.style.ERROR(
                        f'Error al enviar recordatorio a {reserva.email_cliente}: {str(e)}'
                    )
                )

        self.stdout.write(
            self.style.SUCCESS(
                f'Total de recordatorios enviados: {enviados}'
            )
        )

from django.shortcuts import render, redirect, get_object_or_404
from django.views.generic import TemplateView, View
from django.views.decorators.http import require_http_methods
from django.utils.decorators import method_decorator
from django.contrib import messages
from django.contrib.auth.decorators import login_required
from django.db import transaction
