from .services.pricing import PricingService
from .services.email import EmailService


class CheckoutStep1View(TemplateView):
    template_name = 'reservations/checkout_step1.html'

    def get_context_data(self, **kwargs):
        context = super().get_context_data(**kwargs)
        context['form'] = CheckoutStep1Form()
        context['cart_items'] = CartService.get_cart_items(self.request)
        context['cart_total'] = CartService.get_cart_total(self.request)

        # Si el usuario está autenticado, pre-llenar datos
        if self.request.user.is_authenticated:
            context['form'].initial = {
                'nombre_cliente': f'{self.request.user.first_name} {self.request.user.last_name}'.strip() or self.request.user.username,
                'email_cliente': self.request.user.email,
            }

        return context

    def post(self, request, *args, **kwargs):
        form = CheckoutStep1Form(request.POST)

        if CartService.is_cart_empty(request):
            messages.error(request, 'La cesta está vacía. Añade barcos antes de continuar.')
            return redirect('catalog:barco_list')

        if form.is_valid():
            # Guardar datos en sesión
            request.session['checkout_step1'] = {
                'nombre_cliente': form.cleaned_data['nombre_cliente'],
                'email_cliente': form.cleaned_data['email_cliente'],
                'telefono_cliente': form.cleaned_data['telefono_cliente'],
                'fecha_inicio': form.cleaned_data['fecha_inicio'].isoformat(),
                'fecha_fin': form.cleaned_data['fecha_fin'].isoformat(),
            }
            request.session.modified = True
            return redirect('reservations:checkout_step2')

        context = self.get_context_data(**kwargs)
        context['form'] = form
        return render(request, self.template_name, context)


class CheckoutStep2View(TemplateView):
