class TrackReservationView(TemplateView):
    template_name = 'reservations/track.html'

    def get_context_data(self, **kwargs):
        context = super().get_context_data(**kwargs)
        codigo = self.request.GET.get('codigo', '')

        if codigo:
            try:
                reserva = Reserva.objects.get(codigo_seguimiento=codigo)
                context['reserva'] = reserva
                context['historial'] = reserva.historial.all()
            except Reserva.DoesNotExist:
                context['error'] = 'No se encontró la reserva con ese código.'

        return context

    def post(self, request, *args, **kwargs):
        codigo = request.POST.get('codigo', '').strip()

        if codigo:
            return redirect(f'{reverse("reservations:track")}?codigo={codigo}')

        return redirect('reservations:track')


