class CancelReservationView(View):
    @method_decorator(require_http_methods(['POST']))
    @method_decorator(login_required(login_url='accounts:login'))
    def post(self, request, id):
        reserva = get_object_or_404(Reserva, id=id, cliente=request.user)

        if reserva.estado != 'PENDIENTE_DE_PAGO':
            messages.error(request, 'Solo se pueden cancelar reservas en estado PENDIENTE DE PAGO.')
            return redirect('accounts:my_reservations')

        try:
            with transaction.atomic():
                estado_anterior = reserva.estado
                reserva.delete()

                messages.success(request, 'Reserva cancelada exitosamente.')
        except Exception as e:
            messages.error(request, f'Error al cancelar la reserva: {str(e)}')

        return redirect('accounts:my_reservations')

